<template>
 <el-card class="page-card"><div class="page-toolbar"><el-input v-model="query.roleName" placeholder="角色名称" clearable style="width:220px"/><el-button type="primary" @click="load">查询</el-button><span class="spacer"></span><el-button type="primary" :icon="Plus" @click="open()">新增角色</el-button></div><el-table :data="rows" stripe><el-table-column prop="roleName" label="角色名称"/><el-table-column prop="roleCode" label="角色编码"/><el-table-column prop="description" label="描述" min-width="220"/><el-table-column label="状态" width="100"><template #default="s"><el-tag :type="s.row.status===1?'success':'info'">{{s.row.status===1?'启用':'禁用'}}</el-tag></template></el-table-column><el-table-column prop="createTime" label="创建时间" width="180"/><el-table-column label="操作" width="220"><template #default="s"><el-button link type="primary" @click="open(s.row)">编辑</el-button><el-button link type="success" @click="openPermission(s.row)">分配权限</el-button><el-button link type="danger" :disabled="s.row.roleCode==='admin'" @click="remove(s.row)">删除</el-button></template></el-table-column></el-table><el-pagination class="pagination" v-model:current-page="query.pageNum" :page-size="query.pageSize" :total="total" layout="total,prev,pager,next" @change="load"/></el-card>
 <el-dialog v-model="dialog" :title="form.id?'编辑角色':'新增角色'" width="500px"><el-form :model="form" label-width="90px"><el-form-item label="角色名称"><el-input v-model="form.roleName"/></el-form-item><el-form-item label="角色编码"><el-input v-model="form.roleCode" :disabled="form.roleCode==='admin'"/></el-form-item><el-form-item label="描述"><el-input v-model="form.description" type="textarea"/></el-form-item><el-form-item label="状态"><el-switch v-model="form.status" :active-value="1" :inactive-value="0"/></el-form-item></el-form><template #footer><el-button @click="dialog=false">取消</el-button><el-button type="primary" @click="save">保存</el-button></template></el-dialog>
 <el-dialog v-model="permissionDialog" title="分配菜单权限" width="520px"><el-tree ref="treeRef" :data="menus" node-key="id" show-checkbox default-expand-all :props="{label:'menuName',children:'children'}"/><template #footer><el-button @click="permissionDialog=false">取消</el-button><el-button type="primary" @click="savePermission">保存权限</el-button></template></el-dialog>
</template>
<script setup lang="ts">import {nextTick,onMounted,reactive,ref} from 'vue';import {Plus} from '@element-plus/icons-vue';import {ElMessage,ElMessageBox} from 'element-plus';import {getRolePage,createRole,updateRole,deleteRole,getMenuTree,getRoleMenus,saveRoleMenus} from '@/api/system';const query=reactive({pageNum:1,pageSize:10,roleName:''}),rows=ref<any[]>([]),total=ref(0),dialog=ref(false),permissionDialog=ref(false),menus=ref<any[]>([]),treeRef=ref(),currentRole=ref<any>();const form=reactive({id:0,roleName:'',roleCode:'',description:'',status:1});const load=async()=>{const d=await getRolePage(query);rows.value=d.records;total.value=d.total};const open=(r?:any)=>{Object.assign(form,{id:0,roleName:'',roleCode:'',description:'',status:1},r||{});dialog.value=true};const save=async()=>{if(!form.roleName||!form.roleCode)return ElMessage.warning('请填写角色名称和编码');form.id?await updateRole(form.id,form):await createRole(form);ElMessage.success('保存成功');dialog.value=false;load()};const remove=async(r:any)=>{await ElMessageBox.confirm(`确定删除角色“${r.roleName}”吗？`,'提示');await deleteRole(r.id);ElMessage.success('删除成功');load()};const openPermission=async(r:any)=>{currentRole.value=r;permissionDialog.value=true;const ids=await getRoleMenus(r.id);await nextTick();treeRef.value.setCheckedKeys(ids)};const savePermission=async()=>{const ids=[...treeRef.value.getCheckedKeys(),...treeRef.value.getHalfCheckedKeys()];await saveRoleMenus(currentRole.value.id,ids);ElMessage.success('权限已保存');permissionDialog.value=false};onMounted(async()=>{menus.value=await getMenuTree();load()})</script>
<style scoped>.pagination{justify-content:flex-end;margin-top:18px}</style>
